import { ColorRuleProps } from '../../../core/types/color-rule.js';
import { getColorPalette } from '../../../core/utils/get-color-palette.js';

export const getColorFromRule = (rule: ColorRuleProps): string | undefined => {
  if (rule.color) {
    return rule.color;
  }
  if (rule.colorPalette) {
    const palette = getColorPalette('', 0, rule.colorPalette);
    return palette.Default;
  }
  return undefined;
};
